import { createClient } from '@supabase/supabase-js'
import type { Book, Session, PriorityItem, BookNote, Quote, Connection, NoteTab, SearchResult } from '@/types'

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!

export const supabase = createClient(supabaseUrl, supabaseAnonKey)

// Typed helpers

export async function getBooks() {
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .order('created_at', { ascending: false })
  if (error) throw error
  return data as Book[]
}

export async function getBook(id: string) {
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .eq('id', id)
    .single()
  if (error) throw error
  return data as Book
}

export async function createBook(book: Omit<Book, 'id' | 'created_at' | 'updated_at'>) {
  const { data, error } = await supabase
    .from('books')
    .insert(book)
    .select()
    .single()
  if (error) throw error
  return data as Book
}

export async function updateBook(id: string, updates: Partial<Book>) {
  const { data, error } = await supabase
    .from('books')
    .update(updates)
    .eq('id', id)
    .select()
    .single()
  if (error) throw error
  return data as Book
}

export async function deleteBook(id: string) {
  const { error } = await supabase.from('books').delete().eq('id', id)
  if (error) throw error
}

// Sessions

export async function getSessionsForBook(bookId: string) {
  const { data, error } = await supabase
    .from('sessions')
    .select('*')
    .eq('book_id', bookId)
    .order('order_index', { ascending: true })
  if (error) throw error
  return data as Session[]
}

export async function getUpcomingSessions(limit = 20) {
  const today = new Date().toISOString().split('T')[0]
  const { data, error } = await supabase
    .from('sessions')
    .select('*, book:books(*)')
    .gte('scheduled_date', today)
    .eq('is_completed', false)
    .order('scheduled_date', { ascending: true })
    .limit(limit)
  if (error) throw error
  return data as (Session & { book: Book })[]
}

export async function updateSession(id: string, updates: Partial<Session>) {
  const { data, error } = await supabase
    .from('sessions')
    .update(updates)
    .eq('id', id)
    .select()
    .single()
  if (error) throw error
  return data as Session
}

export async function bulkInsertSessions(sessions: Omit<Session, 'id' | 'created_at' | 'updated_at'>[]) {
  const { data, error } = await supabase
    .from('sessions')
    .insert(sessions)
    .select()
  if (error) throw error
  return data as Session[]
}

export async function deleteSessionsForBook(bookId: string) {
  const { error } = await supabase.from('sessions').delete().eq('book_id', bookId)
  if (error) throw error
}

// Priority items

export async function getPriorityItems() {
  const { data, error } = await supabase
    .from('priority_items')
    .select('*')
    .order('scheduled_date', { ascending: true })
  if (error) throw error
  return data as PriorityItem[]
}

export async function createPriorityItem(item: Omit<PriorityItem, 'id' | 'created_at'>) {
  const { data, error } = await supabase
    .from('priority_items')
    .insert(item)
    .select()
    .single()
  if (error) throw error
  return data as PriorityItem
}

export async function updatePriorityItem(id: string, updates: Partial<PriorityItem>) {
  const { data, error } = await supabase
    .from('priority_items')
    .update(updates)
    .eq('id', id)
    .select()
    .single()
  if (error) throw error
  return data as PriorityItem
}

export async function deletePriorityItem(id: string) {
  const { error } = await supabase.from('priority_items').delete().eq('id', id)
  if (error) throw error
}

// Notes

export async function getNotesForBook(bookId: string) {
  const { data, error } = await supabase
    .from('book_notes')
    .select('*')
    .eq('book_id', bookId)
  if (error) throw error
  return data as BookNote[]
}

export async function upsertNote(bookId: string, tab: NoteTab, content: string) {
  const { data, error } = await supabase
    .from('book_notes')
    .upsert({ book_id: bookId, tab, content }, { onConflict: 'book_id,tab' })
    .select()
    .single()
  if (error) throw error
  return data as BookNote
}

// Quotes

export async function getQuotesForBook(bookId: string) {
  const { data, error } = await supabase
    .from('quotes')
    .select('*')
    .eq('book_id', bookId)
    .order('page_number', { ascending: true, nullsFirst: false })
    .order('created_at', { ascending: true })
  if (error) throw error
  return (data as Quote[]).map(q => ({ ...q, tags: q.tags ?? [] }))
}

export async function createQuote(quote: Omit<Quote, 'id' | 'created_at'>) {
  const { data, error } = await supabase
    .from('quotes')
    .insert({ ...quote, tags: quote.tags ?? [] })
    .select()
    .single()
  if (error) throw error
  return { ...(data as Quote), tags: (data as Quote).tags ?? [] }
}

export async function updateQuote(id: string, updates: Partial<Quote>) {
  const { data, error } = await supabase
    .from('quotes')
    .update(updates)
    .eq('id', id)
    .select()
    .single()
  if (error) throw error
  return { ...(data as Quote), tags: (data as Quote).tags ?? [] }
}

export async function deleteQuote(id: string) {
  const { error } = await supabase.from('quotes').delete().eq('id', id)
  if (error) throw error
}

// Connections
// Requires table: connections(id, source_type, source_id, target_type, target_id, note, created_at)
// SQL: CREATE TABLE connections (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, source_type text NOT NULL, source_id text NOT NULL, target_type text NOT NULL, target_id text NOT NULL, note text, created_at timestamptz DEFAULT now());

export async function getConnectionsForSource(sourceId: string) {
  const { data, error } = await supabase
    .from('connections')
    .select('*')
    .eq('source_id', sourceId)
    .order('created_at', { ascending: true })
  if (error) throw error
  return data as Connection[]
}

export async function createConnection(conn: Omit<Connection, 'id' | 'created_at'>) {
  const { data, error } = await supabase
    .from('connections')
    .insert(conn)
    .select()
    .single()
  if (error) throw error
  return data as Connection
}

export async function deleteConnection(id: string) {
  const { error } = await supabase.from('connections').delete().eq('id', id)
  if (error) throw error
}

// Global search

export async function searchAll(query: string): Promise<SearchResult[]> {
  if (!query.trim() || query.trim().length < 2) return []

  const q = query.trim()

  const [quotesRes, notesRes] = await Promise.all([
    supabase
      .from('quotes')
      .select('*, book:books(id, title)')
      .ilike('quote_text', `%${q}%`)
      .limit(30),
    supabase
      .from('book_notes')
      .select('*, book:books(id, title)')
      .ilike('content', `%${q}%`)
      .limit(30),
  ])

  const results: SearchResult[] = []

  for (const quote of quotesRes.data ?? []) {
    const book = quote.book as Book
    results.push({
      type: 'quote',
      id: quote.id,
      bookId: book.id,
      bookTitle: book.title,
      content: quote.quote_text,
      tags: quote.tags ?? [],
      pageNumber: quote.page_number,
    })
  }

  // Also search by tag (client-side filter for partial tag matches)
  const tagQuotesRes = await supabase
    .from('quotes')
    .select('*, book:books(id, title)')
    .contains('tags', [q])
    .limit(20)

  for (const quote of tagQuotesRes.data ?? []) {
    if (results.find(r => r.id === quote.id)) continue
    const book = quote.book as Book
    results.push({
      type: 'quote',
      id: quote.id,
      bookId: book.id,
      bookTitle: book.title,
      content: quote.quote_text,
      tags: quote.tags ?? [],
      pageNumber: quote.page_number,
    })
  }

  for (const note of notesRes.data ?? []) {
    const book = note.book as Book
    results.push({
      type: note.tab === 'insights' ? 'insight' : 'note',
      id: note.id,
      bookId: book.id,
      bookTitle: book.title,
      content: note.content,
      tab: note.tab,
    })
  }

  return results
}
