import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'
import { buildAllSchedules } from '@/lib/scheduling'
import type { Book } from '@/types'

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const { data, error } = await supabase.from('books').select('*').eq('id', id).single()
  if (error) return Response.json({ error: error.message }, { status: 404 })
  return Response.json(data)
}

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const body = await req.json()

  const { data: updatedBook, error } = await supabase
    .from('books')
    .update(body)
    .eq('id', id)
    .select()
    .single()
  if (error) return Response.json({ error: error.message }, { status: 500 })

  // Rebuild schedules whenever sort_order or status changes (affects who is Primary/Secondary)
  if ('sort_order' in body || 'status' in body || 'total_pages' in body || 'current_page' in body) {
    const { data: allBooksData } = await supabase
      .from('books')
      .select('*')
      .eq('status', 'active')

    const allBooks = (allBooksData as Book[]) ?? []

    if (allBooks.length > 0) {
      await supabase
        .from('sessions')
        .delete()
        .in('book_id', allBooks.map(b => b.id))
        .eq('is_completed', false)
    }

    const allRows = buildAllSchedules(allBooks)
    if (allRows.length > 0) {
      const CHUNK = 200
      for (let i = 0; i < allRows.length; i += CHUNK) {
        await supabase.from('sessions').insert(allRows.slice(i, i + CHUNK))
      }
    }
  }

  return Response.json(updatedBook)
}

export async function DELETE(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const { error } = await supabase.from('books').delete().eq('id', id)
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return new Response(null, { status: 204 })
}
